refsection.programlisting:
rows = 120;
cols = 180;
x = ones(rows, 1) * (1:cols);
y = (1:rows)' * ones(1, cols);

surface = 60 + 0.003 .* (x - 90).^2 + 0.006 .* (y - 60).^2 + ..
          8 .* sin(x ./ 12) .* cos(y ./ 10);
minima = ((x - 50).^2 + (y - 40).^2 <= 5^2) | ..
         ((x - 130).^2 + (y - 80).^2 <= 5^2);
imposed = imimposemin(surface, minima);
surfaceImage = uint8(immat2gray(surface) .* 255);
markerView = imoverlaymask(surfaceImage, minima .* 1, [255 0 0], 0.8, %t);

subplot(1, 3, 1);
imshow(immat2gray(surface), hot(64));
xtitle("Original topographic surface");
subplot(1, 3, 2);
imshow(markerView);
xtitle("Requested minima in red");
subplot(1, 3, 3);
imshow(immat2gray(imposed), hot(64));
xtitle("Surface with imposed minima");
